import pymysql
import os
import json

DB_HOST = os.environ.get('DB_HOST')
DB_USER = os.environ.get('DB_USER')
DB_PASSWORD = os.environ.get('DB_PASSWORD')
DB_NAME = os.environ.get('DB_NAME')
DB_PORT = int(os.environ.get('DB_PORT', 3306))

def query_cloud_sql(request):
    request_json = request.get_json(silent=True)
    request_args = request.args

    table = request_args.get('table') or (request_json.get('table') if request_json else None)
    filters_str = request_args.get('filters') or (request_json.get('filters') if request_json else None)

    if not table:
        return 'Missing table parameter', 400

    if not table.isalnum() and '_' not in table:
        return 'Invalid table name', 400

    sql_query = f"SELECT * FROM {table}"
    where_clauses = []

    if filters_str:
        filters_list = filters_str.split(',')

        for filter_item in filters_list:
            parts = filter_item.split(':', 2)
            if len(parts) == 3:
                column, operator, value = parts

                if not column.isalnum() and '_' not in column:
                    return f'Invalid column name in filter: {column}', 400
                
                allowed_operators = ['=', '>', '<', '>=', '<=', 'LIKE', 'NOT LIKE', 'IS NULL', 'IS NOT NULL']
                if operator not in allowed_operators:
                    return f'Invalid operator in filter: {operator}', 400
                
                if value.replace('.', '', 1).isdigit() and operator not in ['LIKE', 'NOT LIKE']:
                    where_clauses.append(f"{column} {operator} {value}")
                elif operator in ['IS NULL', 'IS NOT NULL']:
                    where_clauses.append(f"{column} {operator}")
                else:
                    where_clauses.append(f"{column} {operator} '{value}'")
            else:
                return f'Malformed filter: {filter_item}. Expected "column:operator:value"', 400

    if where_clauses:
        sql_query += " WHERE " + " AND ".join(where_clauses)

    sql_query += " LIMIT 100" 

    try:
        connection = pymysql.connect(
            host=DB_HOST,
            user=DB_USER,
            password=DB_PASSWORD,
            database=DB_NAME,
            port=DB_PORT,
            cursorclass=pymysql.cursors.DictCursor
        )
        with connection.cursor() as cursor:
            cursor.execute(sql_query)
            results = cursor.fetchall()

        return json.dumps(results), 200, {'Content-Type': 'application/json'}

    except pymysql.Error as e:
        print(f"Database error: {e}")
        return f"Database error: {e}", 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return f"An unexpected error occurred: {e}", 500